B.ul=new A.bo(B.Lp,["\uc774\ubaa8\uc9c0 \ubb38\ud654\uc5d0\uc11c \uac00\uc9c0\ub294 \ub354 \uc774\uc0c1 \ucc44\uc18c\ub85c \uc77d\ud788\uc9c0 \uc54a\uc544\uc694. \ucc44\ud305\uc5d0\uc11c \uc9c4\uc9c0\ud558\uac8c \ucc44\uc18c \uc598\uae30\ub97c \ud558\uba74 \uc624\ud574\ubc1b\uae30 \ub531 \uc88b\uc740 \ub2e8\uc5b4.",'"I\'m good with my hands(\uc190\uc7ac\uc8fc \uc88b\uc544\uc694)"\ub294 \uc0c1\ud669\uc5d0 \ub530\ub77c \uc804\ud600 \ub2e4\ub978 \uc7ac\uc8fc \uc790\ub791\uc73c\ub85c \uc54c\uc544\ub4e3\ub294 \uc0ac\ub78c\uc774 \ub9ce\uc544\uc694. \uba74\uc811\uc5d0\uc120 OK, \uc18c\uac1c\ud305\uc5d0\uc120 \uc870\uc2ec.','"Everyone has a first time(\ub204\uad6c\ub098 \ucc98\uc74c\uc740 \uc788\uc8e0)" \u2014 \uc6d0\uc5b4\ubbfc\uc740 \uc885\uc885 \ud2b9\uc815\ud55c "\ucc98\uc74c"\ubd80\ud130 \ub5a0\uc62c\ub824\uc694. \ub2f4\ubc31\ud55c \uc5b5\uc591\uc774 \uc911\uc694\ud574\uc694.','"Deeper(\ub354 \uae4a\uac8c)"\ub294 \ub9d0\ud558\ub294 \ud1a4\uc5d0 \ub530\ub77c \uc6d0\uc608\uc5d0\uc11c \uc544\uc8fc \uba40\uc5b4\uc9c8 \uc218 \uc788\ub294 \ub2e8\uc5b4\uc608\uc694. \uc774 \ub2e8\uc5b4\ub294 \ud1a4\uc774 \uc804\ubd80.','seed bed\ub294 \uba40\uca61\ud55c \uc6d0\uc608 \uc6a9\uc5b4(\ubaa8\ud310)\uc9c0\ub9cc "warm bed(\ub530\ub73b\ud55c \uc7a0\uc790\ub9ac)"\ub77c\uace0 \ud558\uba74 \ub4e3\ub294 \uc0ac\ub78c\uc740 \ub300\ubd80\ubd84 \ub2e4\ub978 \uac83\ubd80\ud130 \ub5a0\uc62c\ub824\uc694.','\ubb38\ub9e5\uc5d0 \ub530\ub77c \uc804\ud600 \ub2e4\ub978 \ub258\uc559\uc2a4\ub85c \ub4e4\ub9ac\ub294 \ub300\ud45c \ub2e8\uc5b4. "no such thing as too wet" \uac19\uc740 \ubb38\uc7a5\uc740 \uc6d0\uc608 \uc598\uae30\uc5ec\ub3c4 \uc6d0\uc5b4\ubbfc\uc774 \uc6c3\uc74c\uc744 \ucc38\uc544\uc694.','"Slow and gentle(\ucc9c\ucc9c\ud788, \ubd80\ub4dc\ub7fd\uac8c)"\uc740 \uc5b4\ub5a4 \uc7a5\ub974\uc758 \ub300\uc0ac\ub85c \uc6cc\ub099 \uc790\uc8fc \uc4f0\uc774\ub294 \uc870\ud569\uc774\ub77c, \uc9c4\uc9c0\ud55c \uc5bc\uad74\ub85c \ub9d0\ud558\uae30 \uc5b4\ub824\uc6b4 \ud45c\ud604\uc774\uc5d0\uc694.','\uae38\ucb49\ud55c \ucc44\uc18c\ub294 \uc601\uc5b4 \ub18d\ub2f4\uc758 \ub2e8\uace8 \uc18c\uc7ac\uc608\uc694. "long and surprisingly heavy"\uae4c\uc9c0 \ubd99\uc73c\uba74 \uc6c3\uc74c\uc744 \ud53c\ud560 \uc218 \uc5c6\uc5b4\uc694.','"Size is not everything(\ud06c\uae30\uac00 \uc804\ubd80\ub294 \uc544\ub2c8\uc5d0\uc694)" \u2014 \uadf8 \uc720\uba85\ud55c \ub17c\uc7c1\uc758 \ubc14\ub85c \uadf8 \ubb38\uc7a5. \ub4a4\uc5d0 "but it never hurts"\uac00 \ubd99\ub294 \uc21c\uac04 \ub18d\ub2f4 \ud655\uc815.','\ub465\uadfc \uacfc\uc77c\uc740 \ubab8\uc744 \ub3cc\ub824 \ub9d0\ud560 \ub54c \uc790\uc8fc \ub3d9\uc6d0\ub3fc\uc694. \ub9c8\ud2b8\uc5d0\uc11c "nice melons"\ub77c\uace0 \uce6d\ucc2c\ud558\uba74 \uc548 \ub418\ub294 \uc774\uc720.','"\uc0b4\uc0b4 \uc950\uc5b4 \ubcf4\uc138\uc694"\ub294 \uacfc\uc77c \uace0\ub974\uae30\uc758 \uc815\uc11d\uc774\uc9c0\ub9cc, \uba5c\ub860 \uc606\uc5d0 \uc4f0\uba74 \ubb38\uc7a5 \uc804\uccb4\uac00 \uc218\uc0c1\ud574\uc838\uc694.',"\uacfc\uc77c\uc5d0\ub294 \uce6d\ucc2c, \uc0ac\ub78c\uc5d0\uac8c \uc4f0\uba74 \uc2e4\ub840\uac00 \ub418\uae30 \uc26c\uc6b4 \ub2e8\uc5b4\uc608\uc694. \uc0ac\ub78c\uc5d0\uac8c\ub294 \uc4f0\uc9c0 \uc54a\ub294 \uac8c \uc548\uc804\ud574\uc694.",'"\ub0a8\ud3b8\uc774 \ubb3c\uc744 \ucda9\ubd84\ud788 \uc548 \uc92c\ub2e4"\ub294 \ubb38\uc7a5\uc774 \uc815\uc6d0 \uc598\uae30\ub85c\ub9cc \ub4e4\ub9ac\uc9c0 \uc54a\ub294 \uac83, \uadf8\uac8c \uc774 \uc774\uc57c\uae30\uc758 \ud3ec\uc778\ud2b8\uc608\uc694.','ride\ub294 \uc624\ub798\uc804\ubd80\ud130 \uc810\uc796\uc9c0 \ubabb\ud55c \ucabd\uc73c\ub85c\ub3c4 \uc4f0\uc5ec \uc628 \ub3d9\uc0ac\uc608\uc694. \uc815\uc791 "like riding a bicycle"\uc740 \uc544\uc8fc \uac74\uc804\ud55c \uad00\uc6a9\uad6c\ub77c \uc774 \ub300\ube44\uac00 \uc6c3\uaca8\uc694.','"\ucd5c\uace0\uc758 \uc6b4\ub3d9(the best exercise)" \u2014 \ubc24\uc5d0 \uc798 \uc7a4\ub2e4\ub294 \ubb38\uc7a5 \ub4a4\uc5d0 \uc624\uba74 \uc5b4\uca50\uc9c0 \uc218\uc0c1\ud558\uac8c \ub4e4\ub9ac\ub294 \uace0\uc804 \ud45c\ud604.'],t.li)
